import { auth } from "@/auth";
import Link from "next/link";
import { redirect } from "next/navigation";
import { isSubscriptionActive, daysRemaining, formatDate } from "@/lib/utils";
import ClientStats from "./ClientStats";
import { userService } from "@/lib/services/UserService";
import { dashboardService } from "@/lib/services/DashboardService";
import { Metadata } from "next";
import React from "react";

export const metadata: Metadata = { title: "Mi Dashboard" };
export const dynamic = "force-dynamic";

export default async function DashboardPage() {
  const session = await auth();
  if (!session?.user?.id) redirect("/auth/login?callbackUrl=/dashboard");

  try {
    const user = await userService.getUserProfile(session.user.id);
    if (!user) redirect("/auth/login?error=user_not_found");

    const subActive = isSubscriptionActive(user.subscriptionExpiry);
    const days = daysRemaining(user.subscriptionExpiry);
    const allowedCareers = user.allowedCareers?.split(",").filter(Boolean) ?? [];
    const isAdmin = user.role === "ADMIN";

    const { careerCount, questionCount, categories, progressMap } =
      await dashboardService.getDashboardStats(
        session.user.id,
        allowedCareers,
        isAdmin
      );

    return (
      <div>
        <div
          className="solid-card animate-fade-in"
          style={{
            padding: "1.5rem",
            marginBottom: "1.5rem",
            background:
              "linear-gradient(135deg, rgba(99,102,241,0.14) 0%, rgba(34,211,238,0.08) 100%)",
            border: "1px solid rgba(99,102,241,0.28)",
          }}
        >
          <div className="page-header" style={{ marginBottom: 0 }}>
            <div>
              <h1 className="page-title">
                Hola, {user.name?.split(" ")[0] || "Estudiante"} 👋
              </h1>
              <p className="page-subtitle">Tu centro de estudio personalizado</p>
            </div>
            <Link href="/quiz" className="btn btn-primary btn-sm">
              Empezar a estudiar
            </Link>
          </div>
        </div>

        {/* Subscription Status */}
        <div
          className="solid-card animate-fade-in"
          style={{
            padding: "1.5rem",
            marginBottom: "1.5rem",
            borderColor: subActive
              ? "rgba(16,185,129,0.2)"
              : "rgba(244,63,94,0.2)",
            background: subActive
              ? "rgba(16,185,129,0.03)"
              : "rgba(244,63,94,0.03)",
          }}
        >
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              flexWrap: "wrap",
              gap: "1rem",
            }}
          >
            <div>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "0.5rem",
                  marginBottom: "0.25rem",
                }}
              >
                <span
                  className={`badge ${
                    subActive ? "badge-success" : "badge-danger"
                  }`}
                >
                  {subActive ? "Suscripción Activa" : "Suscripción Inactiva"}
                </span>
              </div>
              {subActive ? (
                <p
                  style={{
                    fontSize: "0.875rem",
                    color: "var(--text-secondary)",
                  }}
                >
                  Te quedan{" "}
                  <strong style={{ color: "var(--accent-400)" }}>
                    {days} días
                  </strong>{" "}
                  — Expira el {formatDate(user.subscriptionExpiry)}
                </p>
              ) : (
                <p
                  style={{
                    fontSize: "0.875rem",
                    color: "var(--text-secondary)",
                  }}
                >
                  Envía tu comprobante de pago para activar tu acceso a los
                  cuestionarios.
                </p>
              )}
            </div>
            {!subActive && (
              <Link href="/payment" className="btn btn-primary btn-sm">
                Enviar Comprobante
              </Link>
            )}
          </div>
        </div>

        {/* Quick Stats */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
            gap: "1rem",
            marginBottom: "2rem",
          }}
        >
          <div className="stat-card animate-fade-in animate-fade-in-delay-1">
            <div className="stat-value">{careerCount}</div>
            <div className="stat-label">Carreras Disponibles</div>
          </div>
          <div className="stat-card animate-fade-in animate-fade-in-delay-2">
            <div className="stat-value">{questionCount.toLocaleString()}</div>
            <div className="stat-label">Preguntas Totales</div>
          </div>
          <div className="stat-card animate-fade-in animate-fade-in-delay-3">
            <div className="stat-value">{user.streak}</div>
            <div className="stat-label">Días de Racha 🔥</div>
          </div>
        </div>

        {/* @ts-ignore - ClientStats migration pending */}
        <ClientStats categories={categories} progress={progressMap} />

        {/* Quick Actions */}
        <h2
          style={{ fontSize: "1rem", fontWeight: "700", marginBottom: "1rem" }}
        >
          Accesos Rápidos
        </h2>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
            gap: "1rem",
          }}
        >
          <Link
            href="/quiz"
            className="solid-card"
            style={{ padding: "1.5rem", textDecoration: "none" }}
          >
            <div style={{ fontSize: "2rem", marginBottom: "0.75rem" }}>📝</div>
            <h3
              style={{
                fontSize: "1rem",
                fontWeight: "700",
                marginBottom: "0.25rem",
              }}
            >
              Iniciar Cuestionario
            </h3>
            <p style={{ fontSize: "0.8125rem", color: "var(--text-tertiary)" }}>
              Practica con preguntas de tu carrera
            </p>
          </Link>
          <Link
            href="/payment"
            className="solid-card"
            style={{ padding: "1.5rem", textDecoration: "none" }}
          >
            <div style={{ fontSize: "2rem", marginBottom: "0.75rem" }}>💳</div>
            <h3
              style={{
                fontSize: "1rem",
                fontWeight: "700",
                marginBottom: "0.25rem",
              }}
            >
              Gestionar Suscripción
            </h3>
            <p style={{ fontSize: "0.8125rem", color: "var(--text-tertiary)" }}>
              Envía tu comprobante de pago
            </p>
          </Link>
          <Link
            href="/leaderboard"
            className="solid-card"
            style={{ padding: "1.5rem", textDecoration: "none" }}
          >
            <div style={{ fontSize: "2rem", marginBottom: "0.75rem" }}>🏆</div>
            <h3
              style={{
                fontSize: "1rem",
                fontWeight: "700",
                marginBottom: "0.25rem",
              }}
            >
              Ver Leaderboard
            </h3>
            <p style={{ fontSize: "0.8125rem", color: "var(--text-tertiary)" }}>
              Clasificación global de estudiantes
            </p>
          </Link>
          <Link
            href="/suggest"
            className="solid-card"
            style={{ padding: "1.5rem", textDecoration: "none" }}
          >
            <div style={{ fontSize: "2rem", marginBottom: "0.75rem" }}>💡</div>
            <h3
              style={{
                fontSize: "1rem",
                fontWeight: "700",
                marginBottom: "0.25rem",
              }}
            >
              Sugerir Pregunta
            </h3>
            <p style={{ fontSize: "0.8125rem", color: "var(--text-tertiary)" }}>
              Propón preguntas para la comunidad
            </p>
          </Link>
          <Link
            href="/updates"
            className="solid-card"
            style={{
              padding: "1.5rem",
              textDecoration: "none",
              border: "1px solid var(--accent-400)",
              background:
                "linear-gradient(135deg, rgba(34,211,238,0.05) 0%, transparent 100%)",
            }}
          >
            <div style={{ fontSize: "2rem", marginBottom: "0.75rem" }}>🚀</div>
            <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
              <h3
                style={{
                  fontSize: "1rem",
                  fontWeight: "700",
                  marginBottom: "0.25rem",
                }}
              >
                ¿Qué hay de nuevo?
              </h3>
              <span
                className="badge badge-primary"
                style={{ fontSize: "0.625rem" }}
              >
                NUEVO
              </span>
            </div>
            <p style={{ fontSize: "0.8125rem", color: "var(--text-tertiary)" }}>
              Mira las últimas actualizaciones
            </p>
          </Link>
        </div>
      </div>
    );
  } catch (error) {
    console.error("DashboardPage Error:", error);
    return (
      <div
        style={{
          maxWidth: 700,
          margin: "2rem auto",
          padding: "2rem",
          textAlign: "center",
        }}
        className="solid-card"
      >
        <div style={{ fontSize: "3rem", marginBottom: "1rem" }}>⚠️</div>
        <h2
          style={{ fontSize: "1.25rem", fontWeight: 700, marginBottom: "0.75rem" }}
        >
          Error de Conexión
        </h2>
        <p style={{ color: "var(--text-secondary)", marginBottom: "1.5rem" }}>
          No pudimos conectar con el servidor para cargar tus estadísticas.
        </p>
        <a href="/dashboard" className="btn btn-primary">
          Recargar
        </a>
      </div>
    );
  }
}

import { auth } from "@/auth";
import prisma from "@/lib/prisma";
import { redirect } from "next/navigation";
import { isSubscriptionActive, daysRemaining, formatDate } from "@/lib/utils";
import { uploadToUploadThing } from "@/lib/uploadthing";
import { Building } from "lucide-react";
import CopyButton from "@/components/ui/CopyButton";
import { Metadata } from "next";
import React from "react";

export const metadata: Metadata = { title: "Suscripción y Pago" };
export const dynamic = "force-dynamic";

function parseTransferAccounts(rawValue: string | undefined): string[] {
  return String(rawValue || "")
    .split(";")
    .map((item) => item.trim())
    .filter(Boolean);
}

interface TransferAccountDetail {
  bank: string | null;
  accountType: string | null;
  accountNumber: string | null;
  owner: string | null;
  idNumber: string | null;
  raw: string;
}

function parseTransferAccountDetail(account: string): TransferAccountDetail {
  // Split by dash, but handle cases with and without spaces
  const parts = String(account)
    .split(/\s*-\s*/)
    .map((part) => part.trim())
    .filter(Boolean);

  return {
    bank: parts[0] || null,
    accountType: parts[1] || null,
    accountNumber: parts[2] || null,
    owner: parts[3] || null,
    idNumber: parts[4] || null,
    raw: account,
  };
}

async function submitReceipt(formData: FormData) {
  "use server";
  const session = await auth();
  if (!session) redirect("/auth/login");
  const existingPending = await prisma.paymentRequest.findFirst({
    where: { userId: session.user.id, status: "PENDING" },
    select: { id: true },
  });
  if (existingPending) {
    redirect("/payment?error=pending_exists");
  }

  const file = formData.get("receipt") as File | null;
  if (!file || file.size === 0) return;

  const userComment = (formData.get("userComment") as string) || null;
  const requestedCareers =
    (formData.getAll("requestedCareers") as string[])
      .filter(Boolean)
      .join(",") || null;

  let receiptUrl = "";
  try {
    receiptUrl = await uploadToUploadThing(file);
  } catch (e: any) {
    console.error("UploadThing upload failed:", e.message);
    // Fallback or handle error
    redirect("/payment?error=upload_failed");
  }

  await prisma.paymentRequest.create({
    data: {
      userId: session.user.id,
      receiptUrl,
      userComment,
      requestedCareers,
    },
  });

  redirect("/payment?success=true");
}

interface PageProps {
  searchParams: Promise<{
    success?: string;
    error?: string;
    reason?: string;
  }>;
}

export default async function PaymentPage({ searchParams }: PageProps) {
  const session = await auth();
  if (!session?.user) redirect("/auth/login?callbackUrl=/payment");

  const params = await searchParams;
  const success = params?.success === "true";
  const hasPendingError = params?.error === "pending_exists";
  const reason = params?.reason;
  const transferAccounts = parseTransferAccounts(
    process.env.NEXT_PUBLIC_TRANSFER_ACCOUNTS || process.env.TRANSFER_ACCOUNTS
  );

  try {
    const user = await prisma.user.findUnique({
      where: { id: session.user.id },
      select: { subscriptionExpiry: true, allowedCareers: true },
    });

    if (!user) {
      redirect("/auth/login?error=user_not_found");
    }

    const payments = await prisma.paymentRequest.findMany({
      where: { userId: session.user.id },
      orderBy: { createdAt: "desc" },
      take: 10,
    });

    const careers = await prisma.career.findMany({
      orderBy: { name: "asc" },
      select: { id: true, name: true, slug: true, icon: true },
    });

    const subActive = isSubscriptionActive(user.subscriptionExpiry);
    const days = daysRemaining(user.subscriptionExpiry);
    const pendingPayment = payments.find((p) => p.status === "PENDING");
    const allowedList = user.allowedCareers
      ? user.allowedCareers.split(",").filter(Boolean)
      : [];

    return (
      <div style={{ maxWidth: 700, margin: "0 auto" }}>
        <div
          className="page-header"
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "flex-start",
            flexWrap: "wrap",
            gap: "1rem",
          }}
        >
          <div>
            <h1 className="page-title">Suscripción 💳</h1>
            <p className="page-subtitle">Gestiona tu acceso a StudyHub</p>
          </div>
          <a
            href="/dashboard"
            className="btn"
            style={{
              background: "var(--glass-bg)",
              border: "1px solid var(--border-default)",
              fontSize: "0.875rem",
            }}
          >
            ← Volver al inicio
          </a>
        </div>

        {/* Expired warning */}
        {reason === "expired" && !subActive && (
          <div
            className="solid-card animate-fade-in"
            style={{
              padding: "1rem 1.25rem",
              marginBottom: "1.5rem",
              borderColor: "rgba(245,158,11,0.3)",
              background: "rgba(245,158,11,0.05)",
            }}
          >
            <p style={{ fontSize: "0.875rem", color: "var(--warning-400)" }}>
              ⚠️ Tu suscripción ha expirado. Envía un comprobante para
              reactivarla.
            </p>
          </div>
        )}

        {/* Success message */}
        {success && (
          <div
            className="solid-card animate-fade-in"
            style={{
              padding: "1.25rem 1.5rem",
              marginBottom: "1.5rem",
              borderColor: "rgba(16,185,129,0.3)",
              background: "rgba(16,185,129,0.05)",
            }}
          >
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: "0.75rem",
                marginBottom: "0.5rem",
              }}
            >
              <span style={{ fontSize: "1.5rem" }}>✅</span>
              <strong style={{ color: "var(--accent-400)", fontSize: "1rem" }}>
                ¡Comprobante Enviado!
              </strong>
            </div>
            <p
              style={{
                fontSize: "0.875rem",
                color: "var(--text-secondary)",
                lineHeight: 1.6,
              }}
            >
              Tu comprobante ha sido enviado exitosamente. Un administrador lo
              revisará y te habilitará el acceso en un máximo de{" "}
              <strong style={{ color: "var(--text-primary)" }}>24 horas</strong>.
            </p>
          </div>
        )}
        {hasPendingError && (
          <div
            className="solid-card animate-fade-in"
            style={{
              padding: "1rem 1.25rem",
              marginBottom: "1.5rem",
              borderColor: "rgba(245,158,11,0.3)",
              background: "rgba(245,158,11,0.05)",
            }}
          >
            <p style={{ fontSize: "0.875rem", color: "var(--warning-400)" }}>
              Ya tienes un pago pendiente de revisión. No puedes enviar otro
              comprobante todavía.
            </p>
          </div>
        )}

        {/* Pending payment banner */}
        {pendingPayment && !success && (
          <div
            className="solid-card animate-fade-in"
            style={{
              padding: "1.25rem 1.5rem",
              marginBottom: "1.5rem",
              borderColor: "rgba(245,158,11,0.25)",
              background: "rgba(245,158,11,0.04)",
            }}
          >
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: "0.75rem",
                marginBottom: "0.5rem",
              }}
            >
              <span style={{ fontSize: "1.5rem" }}>⏳</span>
              <strong style={{ color: "var(--warning-400)", fontSize: "1rem" }}>
                Pago en Revisión
              </strong>
            </div>
            <p
              style={{
                fontSize: "0.875rem",
                color: "var(--text-secondary)",
                lineHeight: 1.6,
              }}
            >
              Tu comprobante del{" "}
              {new Date(pendingPayment.createdAt).toLocaleDateString("es-ES")}{" "}
              está siendo revisado. Recibirás acceso una vez que sea aprobado.
            </p>
          </div>
        )}

        {/* Current Status */}
        <div
          className="solid-card"
          style={{ padding: "1.25rem 1.5rem", marginBottom: "1.5rem" }}
        >
          <h2
            style={{ fontSize: "1rem", fontWeight: 700, marginBottom: "0.75rem" }}
          >
            Estado Actual
          </h2>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "0.75rem",
              flexWrap: "wrap",
            }}
          >
            <span
              className={`badge ${subActive ? "badge-success" : "badge-danger"}`}
            >
              {subActive ? "Activa" : "Inactiva"}
            </span>
            {subActive && (
              <span
                style={{ fontSize: "0.875rem", color: "var(--text-secondary)" }}
              >
                {days} días restantes — expira {formatDate(user.subscriptionExpiry!)}
              </span>
            )}
          </div>
          {allowedList.length > 0 && (
            <div
              style={{
                marginTop: "0.75rem",
                paddingTop: "0.75rem",
                borderTop: "1px solid var(--border-default)",
              }}
            >
              <div
                style={{
                  fontSize: "0.75rem",
                  color: "var(--text-tertiary)",
                  fontWeight: 600,
                  textTransform: "uppercase",
                  letterSpacing: "0.05em",
                  marginBottom: "0.5rem",
                }}
              >
                Carreras Habilitadas
              </div>
              <div style={{ display: "flex", gap: "0.5rem", flexWrap: "wrap" }}>
                {careers
                  .filter((c) => allowedList.includes(c.slug))
                  .map((c) => (
                    <span key={c.id} className="badge badge-success">
                      {c.icon || "📚"} {c.name}
                    </span>
                  ))}
              </div>
            </div>
          )}
          {(!user.allowedCareers || user.allowedCareers === "") && (
            <div
              style={{
                marginTop: "0.75rem",
                paddingTop: "0.75rem",
                borderTop: "1px solid var(--border-default)",
              }}
            >
              <p style={{ fontSize: "0.8125rem", color: "var(--text-tertiary)" }}>
                ⚠️ Aún no tienes carreras habilitadas. Envía tu comprobante de
                pago y selecciona las carreras que necesitas.
              </p>
            </div>
          )}
        </div>

        {/* Payment Info */}
        <div
          className="solid-card"
          style={{
            padding: "1.25rem 1.5rem",
            marginBottom: "1.5rem",
            border: "1px solid var(--border-default)",
          }}
        >
          <h2
            style={{
              fontSize: "1.125rem",
              fontWeight: 800,
              marginBottom: "1.25rem",
              display: "flex",
              alignItems: "center",
              gap: "0.5rem",
            }}
          >
            <span>💰</span> Información de Pago
          </h2>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
              gap: "1rem",
              marginBottom: "1.5rem",
            }}
          >
            <div
              style={{
                background: "rgba(255,255,255,0.03)",
                borderRadius: "var(--radius-lg)",
                padding: "1.25rem",
                border: "1px solid var(--border-default)",
              }}
            >
              <div
                style={{
                  fontSize: "0.75rem",
                  color: "var(--text-tertiary)",
                  textTransform: "uppercase",
                  fontWeight: 700,
                  letterSpacing: "0.05em",
                  marginBottom: "0.5rem",
                }}
              >
                Precio del Plan
              </div>
              <div
                style={{
                  fontSize: "1.5rem",
                  fontWeight: 900,
                  color: "var(--primary-400)",
                }}
              >
                $10 USD{" "}
                <span
                  style={{
                    fontSize: "0.875rem",
                    color: "var(--text-tertiary)",
                    fontWeight: 500,
                  }}
                >
                  / mes
                </span>
              </div>
            </div>
            <div
              style={{
                background: "rgba(255,255,255,0.03)",
                borderRadius: "var(--radius-lg)",
                padding: "1.25rem",
                border: "1px solid var(--border-default)",
              }}
            >
              <div
                style={{
                  fontSize: "0.75rem",
                  color: "var(--text-tertiary)",
                  textTransform: "uppercase",
                  fontWeight: 700,
                  letterSpacing: "0.05em",
                  marginBottom: "0.5rem",
                }}
              >
                Tiempo de Espera
              </div>
              <div
                style={{
                  fontSize: "1.5rem",
                  fontWeight: 900,
                  color: "var(--accent-400)",
                }}
              >
                &lt; 24h{" "}
                <span
                  style={{
                    fontSize: "0.875rem",
                    color: "var(--text-tertiary)",
                    fontWeight: 500,
                  }}
                >
                  aprobación
                </span>
              </div>
            </div>
          </div>

          <div style={{ marginBottom: "1.5rem" }}>
            <h3
              style={{
                fontSize: "0.875rem",
                fontWeight: 800,
                color: "var(--text-secondary)",
                textTransform: "uppercase",
                letterSpacing: "0.05em",
                marginBottom: "1rem",
                display: "flex",
                alignItems: "center",
                gap: "0.5rem",
              }}
            >
              <span
                style={{
                  width: "20px",
                  height: "1px",
                  background: "var(--border-default)",
                }}
              ></span>
              Cuentas para Transferir
              <span
                style={{
                  flex: 1,
                  height: "1px",
                  background: "var(--border-default)",
                }}
              ></span>
            </h3>

            {transferAccounts.length > 0 ? (
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
                  gap: "1.25rem",
                }}
              >
                {transferAccounts.map((account) => {
                  const detail = parseTransferAccountDetail(account);

                  // Color Logic
                  const isPichincha = detail.bank
                    ?.toLowerCase()
                    .includes("pichincha");
                  const isProdubanco = detail.bank
                    ?.toLowerCase()
                    .includes("produbanco");

                  let cardAccent = "var(--primary-400)";
                  let cardBorder = "rgba(14, 165, 233, 0.15)";

                  if (isPichincha) {
                    cardAccent = "var(--warning-400)";
                    cardBorder = "rgba(245, 158, 11, 0.15)";
                  } else if (isProdubanco) {
                    cardAccent = "var(--success-400)";
                    cardBorder = "rgba(16, 185, 129, 0.15)";
                  }

                  return (
                    <div
                      key={account}
                      className="animate-fade-in"
                      style={{
                        background: "var(--bg-tertiary)",
                        border: `1px solid ${cardBorder}`,
                        borderRadius: "var(--radius-xl)",
                        padding: "1.5rem",
                        display: "flex",
                        flexDirection: "column",
                        gap: "1.25rem",
                        position: "relative",
                        overflow: "hidden",
                        boxShadow: "0 10px 30px -15px rgba(0,0,0,0.4)",
                      }}
                    >
                      {/* Decorative bank indicator */}
                      <div
                        style={{
                          position: "absolute",
                          top: 0,
                          left: 0,
                          width: "100%",
                          height: "4px",
                          background: cardAccent,
                        }}
                      />

                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: "0.75rem",
                        }}
                      >
                        <div
                          style={{
                            width: "44px",
                            height: "44px",
                            borderRadius: "12px",
                            background: `${cardAccent}15`,
                            display: "grid",
                            placeItems: "center",
                            color: cardAccent,
                            border: `1px solid ${cardAccent}30`,
                          }}
                        >
                          <Building size={24} />
                        </div>
                        <div>
                          <div
                            style={{
                              fontSize: "1.125rem",
                              fontWeight: 900,
                              color: "white",
                              letterSpacing: "-0.01em",
                            }}
                          >
                            {detail.bank || "Banco"}
                          </div>
                          <div
                            style={{
                              fontSize: "0.75rem",
                              color: "var(--text-tertiary)",
                              textTransform: "uppercase",
                              fontWeight: 800,
                              letterSpacing: "0.05em",
                            }}
                          >
                            {detail.accountType || "Cuenta"}
                          </div>
                        </div>
                      </div>

                      <div
                        style={{
                          display: "grid",
                          gap: "0.75rem",
                          marginTop: "0.5rem",
                        }}
                      >
                        {/* Account Number Card */}
                        <div
                          style={{
                            background: "rgba(0,0,0,0.25)",
                            borderRadius: "var(--radius-lg)",
                            padding: "1rem",
                            border: "1px solid rgba(255,255,255,0.05)",
                            position: "relative",
                          }}
                        >
                          <div
                            style={{
                              fontSize: "0.625rem",
                              color: "var(--text-tertiary)",
                              fontWeight: 800,
                              textTransform: "uppercase",
                              marginBottom: "0.25rem",
                            }}
                          >
                            Número de Cuenta
                          </div>
                          <div
                            style={{
                              display: "flex",
                              justifyContent: "space-between",
                              alignItems: "center",
                            }}
                          >
                            <span
                              style={{
                                fontSize: "1.125rem",
                                fontWeight: 800,
                                color: cardAccent,
                                fontFamily: "monospace",
                              }}
                            >
                              {detail.accountNumber || "---"}
                            </span>
                            <CopyButton text={detail.accountNumber || ""} />
                          </div>
                        </div>

                        <div
                          style={{
                            display: "grid",
                            gridTemplateColumns: "1.2fr 0.8fr",
                            gap: "0.75rem",
                          }}
                        >
                          <div
                            style={{
                              background: "rgba(255,255,255,0.02)",
                              borderRadius: "var(--radius-md)",
                              padding: "0.75rem",
                              border: "1px solid rgba(255,255,255,0.03)",
                              minWidth: 0,
                            }}
                          >
                            <div
                              style={{
                                fontSize: "0.625rem",
                                color: "var(--text-tertiary)",
                                fontWeight: 800,
                                textTransform: "uppercase",
                                marginBottom: "0.125rem",
                              }}
                            >
                              Titular
                            </div>
                            <div
                              style={{
                                fontSize: "0.8125rem",
                                fontWeight: 700,
                                whiteSpace: "nowrap",
                                overflow: "hidden",
                                textOverflow: "ellipsis",
                              }}
                              title={detail.owner || ""}
                            >
                              {detail.owner || "---"}
                            </div>
                          </div>
                          <div
                            style={{
                              background: "rgba(255,255,255,0.02)",
                              borderRadius: "var(--radius-md)",
                              padding: "0.75rem",
                              border: "1px solid rgba(255,255,255,0.03)",
                              minWidth: 0,
                            }}
                          >
                            <div
                              style={{
                                fontSize: "0.625rem",
                                color: "var(--text-tertiary)",
                                fontWeight: 800,
                                textTransform: "uppercase",
                                marginBottom: "0.125rem",
                              }}
                            >
                              CI / RIF
                            </div>
                            <div
                              style={{
                                fontSize: "0.8125rem",
                                fontWeight: 700,
                                whiteSpace: "nowrap",
                                overflow: "hidden",
                                textOverflow: "ellipsis",
                              }}
                              title={detail.idNumber || ""}
                            >
                              {detail.idNumber || "---"}
                            </div>
                          </div>
                        </div>

                        <CopyButton
                          text={`${detail.bank} - ${detail.accountNumber} - ${detail.owner} - ${detail.idNumber}`}
                          label="Copiar todos los datos"
                          fullWidth={true}
                        />
                      </div>
                    </div>
                  );
                })}
              </div>
            ) : (
              <div
                style={{
                  textAlign: "center",
                  padding: "3rem 1rem",
                  background: "rgba(255,255,255,0.01)",
                  borderRadius: "var(--radius-lg)",
                  border: "1px dashed var(--border-default)",
                }}
              >
                <p style={{ fontSize: "0.875rem", color: "var(--text-tertiary)" }}>
                  No hay cuentas configuradas actualmente.
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Upload Form */}
        <div
          className="solid-card"
          style={{
            padding: "1.25rem 1.5rem",
            marginBottom: "1.5rem",
            opacity: pendingPayment ? 0.65 : 1,
          }}
        >
          <h2
            style={{ fontSize: "1rem", fontWeight: 700, marginBottom: "1rem" }}
          >
            📷 Enviar Comprobante
          </h2>
          {pendingPayment && (
            <div
              style={{
                marginBottom: "1rem",
                fontSize: "0.8125rem",
                color: "var(--warning-400)",
              }}
            >
              Ya tienes un comprobante pendiente de revisión. Debes esperar la
              respuesta del administrador antes de volver a enviar otro pago.
            </div>
          )}
          <form action={submitReceipt}>
            {/* Receipt upload */}
            <div style={{ marginBottom: "1rem" }}>
              <label className="label">Foto del Comprobante *</label>
              <input
                type="file"
                name="receipt"
                accept="image/*"
                required
                className="input"
                style={{ padding: "0.5rem" }}
                disabled={!!pendingPayment}
              />
            </div>

            {/* Career selection */}
            <div style={{ marginBottom: "1rem" }}>
              <label className="label">
                ¿Qué carreras necesitas? (selecciona las que apliquen)
              </label>
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(auto-fill, minmax(180px, 1fr))",
                  gap: "0.5rem",
                  marginTop: "0.5rem",
                }}
              >
                {careers.map((c) => (
                  <label
                    key={c.id}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: "0.5rem",
                      padding: "0.625rem 0.75rem",
                      background: "var(--bg-tertiary)",
                      borderRadius: "var(--radius-md)",
                      cursor: "pointer",
                      border: "1px solid var(--border-default)",
                      fontSize: "0.8125rem",
                      fontWeight: 500,
                      transition: "all 0.15s ease",
                    }}
                  >
                    <input
                      type="checkbox"
                      name="requestedCareers"
                      value={c.slug}
                      defaultChecked={allowedList.includes(c.slug)}
                      disabled={!!pendingPayment}
                      style={{
                        accentColor: "var(--accent-400)",
                        width: 16,
                        height: 16,
                      }}
                    />
                    <span>
                      {c.icon || "📚"} {c.name}
                    </span>
                  </label>
                ))}
              </div>
            </div>

            {/* User comment */}
            <div style={{ marginBottom: "1.25rem" }}>
              <label className="label">Comentario (opcional)</label>
              <textarea
                name="userComment"
                placeholder="Escribe cualquier información relevante sobre tu pago, solicitud o dudas..."
                className="input textarea"
                style={{ minHeight: 80, resize: "vertical" }}
                disabled={!!pendingPayment}
              />
            </div>

            <button
              type="submit"
              className="btn btn-primary"
              style={{ width: "100%" }}
              disabled={!!pendingPayment}
            >
              {pendingPayment ? "Comprobante en Revisión" : "Enviar Comprobante"}
            </button>
          </form>
        </div>

        {/* Payment History */}
        {payments.length > 0 && (
          <div className="solid-card" style={{ overflow: "hidden" }}>
            <div
              style={{
                padding: "1rem 1.25rem",
                borderBottom: "1px solid var(--border-default)",
              }}
            >
              <h2 style={{ fontSize: "1rem", fontWeight: 700 }}>Historial</h2>
            </div>
            <div style={{ display: "flex", flexDirection: "column" }}>
              {payments.map((p) => (
                <div
                  key={p.id}
                  style={{
                    padding: "1rem 1.25rem",
                    borderBottom: "1px solid var(--border-default)",
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "flex-start",
                    flexWrap: "wrap",
                    gap: "0.5rem",
                  }}
                >
                  <div>
                    <div
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "0.5rem",
                        marginBottom: "0.25rem",
                      }}
                    >
                      <span
                        className={`badge ${
                          p.status === "APPROVED"
                            ? "badge-success"
                            : p.status === "REJECTED"
                            ? "badge-danger"
                            : "badge-warning"
                        }`}
                      >
                        {p.status === "APPROVED"
                          ? "✅ Aprobado"
                          : p.status === "REJECTED"
                          ? "❌ Rechazado"
                          : "⏳ Pendiente"}
                      </span>
                      <span
                        style={{ fontSize: "0.75rem", color: "var(--text-tertiary)" }}
                      >
                        {new Date(p.createdAt).toLocaleDateString("es-ES")}
                      </span>
                    </div>
                    {p.requestedCareers && (
                      <div
                        style={{
                          fontSize: "0.75rem",
                          color: "var(--text-tertiary)",
                          marginTop: "0.25rem",
                        }}
                      >
                        Carreras solicitadas:{" "}
                        {p.requestedCareers.split(",").join(", ")}
                      </div>
                    )}
                    {p.userComment && (
                      <div
                        style={{
                          fontSize: "0.8125rem",
                          color: "var(--text-secondary)",
                          marginTop: "0.25rem",
                          fontStyle: "italic",
                        }}
                      >
                        &ldquo;{p.userComment}&rdquo;
                      </div>
                    )}
                    {p.status === "REJECTED" && p.adminNotes && (
                      <div
                        style={{
                          fontSize: "0.8125rem",
                          color: "var(--danger-400)",
                          marginTop: "0.375rem",
                          padding: "0.5rem 0.75rem",
                          background: "rgba(244,63,94,0.06)",
                          borderRadius: "var(--radius-sm)",
                          border: "1px solid rgba(244,63,94,0.15)",
                        }}
                      >
                        <strong>Motivo:</strong> {p.adminNotes}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  } catch (error) {
    console.error("PaymentPage Error:", error);
    return (
      <div
        style={{
          maxWidth: 700,
          margin: "2rem auto",
          padding: "2rem",
          textAlign: "center",
        }}
        className="solid-card"
      >
        <div style={{ fontSize: "3rem", marginBottom: "1rem" }}>⚠️</div>
        <h2
          style={{ fontSize: "1.25rem", fontWeight: 700, marginBottom: "0.75rem" }}
        >
          Error de Conexión
        </h2>
        <p style={{ color: "var(--text-secondary)", marginBottom: "1.5rem" }}>
          No pudimos conectar con el servidor de pagos. Por favor, intenta
          recargar la página.
        </p>
        <a href="/payment" className="btn btn-primary">
          Recargar Página
        </a>
      </div>
    );
  }
}

