import { notFound } from "next/navigation";
import { auth } from "@/auth";
import QuizClient from "@/components/quiz/QuizClient";
import { quizService } from "@/lib/services/QuizService";
import { userService } from "@/lib/services/UserService";
import { Metadata } from "next";
import prisma from "@/lib/prisma";
import React from "react";

export const dynamic = "force-dynamic";

export async function generateMetadata({
  params,
}: {
  params: Promise<{ categoryId: string }>;
}): Promise<Metadata> {
  const { categoryId } = await params;
  const category = await prisma.category.findUnique({
    where: { id: categoryId },
    include: { career: { select: { name: true } } },
  });
  if (!category) return { title: "Cuestionario" };
  return { title: `${category.name} — ${category.career.name}` };
}

export default async function QuizPage({
  params,
}: {
  params: Promise<{ categoryId: string }>;
}) {
  const { categoryId } = await params;
  const session = await auth();

  if (!session?.user?.id) notFound();

  try {
    // 1. Verify Access
    const isAdmin = session.user.role === "ADMIN";
    const user = await userService.getUserProfile(session.user.id);
    if (!user) notFound();

    const isSubActive =
      user.subscriptionExpiry && new Date(user.subscriptionExpiry) > new Date();

    if (!isAdmin) {
      if (!isSubActive || !user.allowedCareers || user.allowedCareers.trim() === "") {
        notFound();
      }
    }

    // 2. Fetch Data via Service
    const quizData = await quizService.getQuizData(
      categoryId,
      session.user.id,
      isAdmin
    );

    if (!quizData || (quizData.questions.length === 0 && !quizData.category.theory)) {
      notFound();
    }

    // Verify career access for regular users
    if (!isAdmin) {
      const allowed = user.allowedCareers?.split(",").filter(Boolean) ?? [];
      if (!allowed.includes(quizData.category.career.slug)) {
        notFound();
      }
    }

    // 3. Fetch Sidebar Data (Careers & Categories)
    const careers = await prisma.career.findMany({
      orderBy: { name: "asc" },
      include: {
        categories: {
          orderBy: { name: "asc" },
          select: { id: true, name: true },
        },
      },
    });

    let filteredCareers = careers;
    if (!isAdmin) {
      const allowed = user.allowedCareers?.split(",").filter(Boolean) ?? [];
      filteredCareers = careers.filter((c) => allowed.includes(c.slug));
    }

    return (
      <div>
        {/* @ts-ignore - QuizClient migration pending */}
        <QuizClient
          questions={quizData.questions}
          theory={quizData.category.theory}
          categoryName={quizData.category.name}
          careerName={quizData.category.career.name}
          careers={filteredCareers}
          currentCareerId={quizData.category.career.id}
          categoryId={categoryId}
          totalQuestionsInCategory={quizData.totalQuestionsInCategory}
          initialCompletedCount={quizData.initialCompletedCount}
          isAdmin={isAdmin}
        />
      </div>
    );
  } catch (error) {
    console.error("QuizPage Error:", error);
    return (
      <div style={{ padding: "4rem 2rem", textAlign: "center" }}>
        <h1 style={{ fontSize: "2rem", marginBottom: "1rem" }}>
          ⚠️ Error de Conexión
        </h1>
        <p
          style={{
            color: "var(--text-tertiary)",
            maxWidth: "500px",
            margin: "0 auto",
          }}
        >
          No pudimos conectar con la base de datos. Por favor, verifica que el
          servidor de base de datos esté funcionando e inténtalo de nuevo.
        </p>
      </div>
    );
  }
}

import prisma from "@/lib/prisma";
import Link from "next/link";
import { redirect } from "next/navigation";
import { auth } from "@/auth";
import QuizAgreement from "@/components/quiz/QuizAgreement";
import ClientStats from "@/app/(app)/dashboard/ClientStats";
import GlobalSearch from "@/components/ui/GlobalSearch";
import CareerSelector from "@/components/quiz/CareerSelector";
import { userService } from "@/lib/services/UserService";
import { dashboardService } from "@/lib/services/DashboardService";
import { Metadata } from "next";
import React from "react";

export const metadata: Metadata = { title: "Cuestionarios" };
export const dynamic = "force-dynamic";

export default async function QuizSelectorPage({
  searchParams,
}: {
  searchParams: Promise<{ career?: string }>;
}) {
  const params = await searchParams;
  const selectedCareerSlug = params.career;

  const session = await auth();
  if (!session?.user?.id) redirect("/auth/login?callbackUrl=/quiz");

  try {
    const user = await userService.getUserProfile(session.user.id);
    if (!user) redirect("/auth/login?error=user_not_found");

    const isSubActive =
      user.subscriptionExpiry && new Date(user.subscriptionExpiry) > new Date();
    const isAdmin = user.role === "ADMIN";

    let careers = await prisma.career.findMany({
      orderBy: { name: "asc" },
      include: {
        categories: {
          orderBy: { name: "asc" },
          include: {
            _count: { select: { questions: true } },
          },
        },
      },
    });

    if (!isAdmin) {
      if (!user.allowedCareers || user.allowedCareers.trim() === "") {
        careers = [];
      } else {
        const allowed = user.allowedCareers.split(",").filter(Boolean);
        careers = careers.filter((c) => allowed.includes(c.slug));
      }
    }

    const noAccess =
      !isAdmin &&
      (!isSubActive ||
        !user.allowedCareers ||
        user.allowedCareers.trim() === "");

    const visibleCareerSlugs = careers.map((career) => career.slug);

    const { categories: allCategories, progressMap } =
      await dashboardService.getDashboardStats(
        session.user.id,
        visibleCareerSlugs,
        isAdmin
      );

    return (
      <div
        className="quiz-selector-page"
        style={{ maxWidth: "1200px", margin: "0 auto", padding: "1.5rem 1.25rem" }}
      >
        <QuizAgreement />
        <header style={{ marginBottom: "2rem", width: "100%" }}>
          <div style={{ marginBottom: "1.25rem" }}>
            <h1
              className="page-title"
              style={{
                fontSize: "clamp(1.75rem, 6vw, 2.25rem)",
                margin: 0,
                textAlign: "left",
                lineHeight: 1.1,
              }}
            >
              Hola, {user.name?.trim().split(/\s+/)[0] || "Estudiante"} 👋
            </h1>
            <p
              className="page-subtitle"
              style={{
                fontSize: "0.9375rem",
                margin: "0.375rem 0 0 0",
                textAlign: "left",
                opacity: 0.7,
              }}
            >
              Panel de estudio interactivo
            </p>
          </div>

          <div
            className="quiz-header-actions"
            style={{
              display: "flex",
              gap: "0.625rem",
              overflowX: "auto",
              padding: "0.25rem 0 0.75rem 0",
              scrollbarWidth: "none",
              msOverflowStyle: "none",
            }}
          >
            <style
              dangerouslySetInnerHTML={{
                __html: `.quiz-header-actions::-webkit-scrollbar { display: none; }`,
              }}
            />
            {[
              { href: "/quiz/repaso", icon: "🧠", label: "Repaso" },
              { href: "/badges", icon: "🏅", label: "Logros" },
              { href: "/leaderboard", icon: "🏆", label: "Ranking" },
              { href: "/dashboard", icon: "🏠", label: "Inicio" },
              { href: "/settings", icon: "⚙️", label: "Ajustes" },
            ].map((item) => (
              <Link
                key={item.href}
                href={item.href}
                className="btn btn-secondary btn-sm"
                style={{
                  borderRadius: "var(--radius-full)",
                  whiteSpace: "nowrap",
                  padding: "0.5rem 1rem",
                  background: "var(--bg-tertiary)",
                  border: "1px solid var(--border-default)",
                }}
              >
                {item.icon} {item.label}
              </Link>
            ))}
          </div>
        </header>

        <div
          style={{
            marginBottom: "2rem",
            display: "flex",
            justifyContent: "center",
          }}
        >
          {/* @ts-ignore - GlobalSearch migration pending */}
          <GlobalSearch categories={allCategories} />
        </div>

        <h2
          style={{
            fontSize: "1.25rem",
            fontWeight: "700",
            marginBottom: "0.5rem",
            marginTop: "0",
          }}
        >
          ¿Qué quieres estudiar hoy?
        </h2>
        <p
          style={{
            fontSize: "0.875rem",
            color: "var(--text-tertiary)",
            marginBottom: "1rem",
          }}
        >
          Elige primero tu carrera y luego revisa tus estadísticas.
        </p>

        {!noAccess && (
          <div id="career-selector" style={{ marginBottom: "2rem" }}>
            {/* @ts-ignore - CareerSelector migration pending */}
            <CareerSelector
              careers={careers}
              selectedCareerSlug={selectedCareerSlug}
            />
          </div>
        )}
        {!noAccess && (
          <ClientStats
            categories={allCategories as any}
            progress={progressMap}
            user={user}
          />
        )}

        <h2
          style={{
            fontSize: "1.25rem",
            fontWeight: "700",
            marginBottom: "1.25rem",
            marginTop: noAccess ? "0" : "1.5rem",
          }}
        >
          Módulos Disponibles
        </h2>

        {noAccess ? (
          <div
            className="solid-card"
            style={{ padding: "2.5rem 2rem", textAlign: "center" }}
          >
            <div style={{ fontSize: "3rem", marginBottom: "1rem", opacity: 0.6 }}>
              🔒
            </div>
            <h2
              style={{
                fontSize: "1.25rem",
                fontWeight: 700,
                marginBottom: "0.75rem",
              }}
            >
              Acceso No Habilitado
            </h2>
            <p
              style={{
                color: "var(--text-secondary)",
                fontSize: "0.9375rem",
                lineHeight: 1.6,
                maxWidth: 450,
